module top_module(
    input Inv_x,
    input y,
    output z
);
    assign z = Inv_x | y;
endmodule

module H(
    input Inv_x,
    input y,
    output z
);
    assign z = Inv_x | y;
endmodule

module top_module(
    input Inv_x,
    input y,
    output z
);
    wire g1_out, g2_out, h1_out, h2_out;
    wire or_out, and_out;

    G g1(.Inv_x(Inv_x), .y(y), .z(g1_out));
    G g2(.Inv_x(Inv_x), .y(y), .z(g2_out));
    H h1(.Inv_x(Inv_x), .y(y), .z(h1_out));
    H h2(.Inv_x(Inv_x), .y(y), .z(h2_out));

    assign or_out = g1_out | h1_out;
    assign and_out = g2_out & h2_out;

    assign z = or_out ^ and_out;
endmodule
